import { useEffect, useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { transformToFinancialProduct, generateDecisionInsight, projectReturn, formatPKR, formatReturn } from '../utils/finance';
import { RiskBadge, CategoryBadge, LiquidityBadge, HorizonBadge, ReturnDisplay } from '../components/Badges';
import { usePortfolio } from '../contexts/PortfolioContext';
import './ProductDetail.css';

export default function ProductDetail() {
  const { id }    = useParams();
  const navigate  = useNavigate();
  const [product, setProduct]       = useState(null);
  const [allProducts, setAll]       = useState([]);
  const [loading, setLoading]       = useState(true);
  const [notFound, setNotFound]     = useState(false);
  const [investAmount, setInvest]   = useState('');
  const [compareWith, setCompare]   = useState('');
  const [compareProduct, setCP]     = useState(null);
  const { isInPortfolio, addToPortfolio, removeFromPortfolio } = usePortfolio();
  const [justAdded, setJustAdded]   = useState(false);

  useEffect(() => {
    fetch('https://fakestoreapi.com/products')
      .then(r => r.json())
      .then(data => {
        const all = data.map(transformToFinancialProduct);
        setAll(all);
        const found = all.find(p => String(p.id) === String(id));
        if (!found) { setNotFound(true); setLoading(false); return; }
        setProduct(found);
        setInvest(String(found.minInvestment));
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, [id]);

  useEffect(() => {
    if (!compareWith || !allProducts.length) { setCP(null); return; }
    const cp = allProducts.find(p => String(p.id) === String(compareWith));
    setCP(cp || null);
  }, [compareWith, allProducts]);

  function handlePortfolio() {
    if (!product) return;
    if (isInPortfolio(product.id)) {
      removeFromPortfolio(product.id);
    } else {
      addToPortfolio(product, Number(investAmount) || product.minInvestment);
      setJustAdded(true);
      setTimeout(() => setJustAdded(false), 2000);
    }
  }

  if (loading) return <div className="page"><div className="loading-wrap"><div className="spinner" /><p>Loading…</p></div></div>;
  if (notFound) return (
    <div className="page">
      <div className="container" style={{ paddingTop: 80, textAlign: 'center' }}>
        <h2 style={{ color: 'var(--clr-high)', marginBottom: 12 }}>Product Not Found</h2>
        <p style={{ color: 'var(--clr-text-dim)', marginBottom: 24 }}>No product exists with ID: {id}</p>
        <Link to="/products" className="btn btn-primary">← Back to Products</Link>
      </div>
    </div>
  );
  if (!product) return null;

  const insights = generateDecisionInsight(product);
  const inPortfolio = isInPortfolio(product.id);
  const amount = Number(investAmount) || product.minInvestment;

  const projections = [1, 3, 5, 10].map(y => ({
    year: y,
    value: projectReturn(amount, product.expectedReturn, y),
    profit: projectReturn(amount, product.expectedReturn, y) - amount,
  }));

  const riskPct = { low: 25, medium: 60, high: 90 }[product.riskLevel] || 50;

  return (
    <div className="page page-enter">
      <div className="container">
        {/* Breadcrumb */}
        <div className="pd-breadcrumb">
          <Link to="/products">Products</Link>
          <span>›</span>
          <span>{product.name}</span>
        </div>

        <div className="pd-layout">
          {/* LEFT: Product Info */}
          <div className="pd-main">
            <div className="pd-card card">
              <div className="pd-top">
                <div className="pd-badges">
                  <CategoryBadge category={product.category} />
                  <RiskBadge riskLevel={product.riskLevel} size="lg" />
                </div>
                <h1 className="pd-name">{product.name}</h1>
                <div className="pd-return-big">
                  <span className="pd-return-num">
                    <ReturnDisplay value={product.expectedReturn} showLabel={false} />
                  </span>
                  <span className="pd-return-label">Expected Annual Return</span>
                </div>
              </div>

              <div className="pd-attrs">
                {[
                  { label: 'Min. Investment', val: formatPKR(product.minInvestment) },
                  { label: 'Liquidity', val: <LiquidityBadge liquidity={product.liquidity} /> },
                  { label: 'Time Horizon', val: <HorizonBadge timeHorizon={product.timeHorizon} /> },
                  { label: 'Category', val: product.category.toUpperCase() },
                ].map(a => (
                  <div key={a.label} className="pd-attr-row">
                    <span className="pd-attr-label">{a.label}</span>
                    <span className="pd-attr-val">{a.val}</span>
                  </div>
                ))}
              </div>

              <p className="pd-desc">{product.description}</p>

              {/* Risk Visualization */}
              <div className="pd-risk-vis">
                <div className="pd-risk-header">
                  <span className="pd-risk-title">Risk Meter</span>
                  <RiskBadge riskLevel={product.riskLevel} />
                </div>
                <div className="pd-risk-track">
                  <div className="pd-risk-fill" style={{ width: `${riskPct}%`, background: `var(--clr-${product.riskLevel})` }} />
                  <div className="pd-risk-labels">
                    <span>Low</span><span>Medium</span><span>High</span>
                  </div>
                </div>
              </div>

              {/* Portfolio Action */}
              <div className="pd-actions">
                <button
                  className={`btn ${inPortfolio ? 'btn-danger' : justAdded ? 'btn-primary' : 'btn-primary'}`}
                  onClick={handlePortfolio}
                  style={{ flex: 1 }}
                >
                  {justAdded ? '✓ Added to Portfolio!' : inPortfolio ? '✕ Remove from Portfolio' : '+ Add to Portfolio'}
                </button>
                <Link to="/portfolio" className="btn btn-outline">View Portfolio</Link>
              </div>
            </div>

            {/* Decision Insights */}
            <div className="pd-insights card">
              <h3 className="pd-section-title">📊 Decision Insights</h3>
              <p className="pd-insights-sub">Who is this product suitable for?</p>
              <ul className="pd-insights-list">
                {insights.map((ins, i) => (
                  <li key={i} className="pd-insight-item">
                    <span className="pd-insight-dot" />
                    {ins}
                  </li>
                ))}
              </ul>
            </div>
          </div>

          {/* RIGHT: Calculator + Compare */}
          <div className="pd-side">
            {/* Return Calculator */}
            <div className="pd-calc card">
              <h3 className="pd-section-title">🧮 Return Calculator</h3>
              <div className="form-group" style={{ marginBottom: 16 }}>
                <label className="form-label">Investment Amount (PKR)</label>
                <input
                  type="number"
                  className="form-input"
                  value={investAmount}
                  min={product.minInvestment}
                  step={1000}
                  onChange={e => setInvest(e.target.value)}
                  placeholder={`Min: ${formatPKR(product.minInvestment)}`}
                />
                {Number(investAmount) > 0 && Number(investAmount) < product.minInvestment && (
                  <p className="form-error">Min investment is {formatPKR(product.minInvestment)}</p>
                )}
              </div>

              <div className="pd-projections">
                {projections.map(p => (
                  <div key={p.year} className="pd-proj-row">
                    <span className="pd-proj-year">{p.year}yr</span>
                    <div className="pd-proj-bar-wrap">
                      <div className="pd-proj-bar" style={{ width: `${Math.min(100, (p.profit / p.value) * 200)}%` }} />
                    </div>
                    <div className="pd-proj-vals">
                      <span className="pd-proj-total">{formatPKR(p.value)}</span>
                      <span className="pd-proj-profit">+{formatPKR(p.profit)}</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Compare */}
            <div className="pd-compare card">
              <h3 className="pd-section-title">⚖️ Compare Products</h3>
              <div className="form-group" style={{ marginBottom: 16 }}>
                <label className="form-label">Compare with</label>
                <select
                  className="form-select"
                  value={compareWith}
                  onChange={e => setCompare(e.target.value)}
                >
                  <option value="">— Select a product —</option>
                  {allProducts.filter(p => p.id !== product.id).map(p => (
                    <option key={p.id} value={p.id}>{p.name.substring(0, 40)}</option>
                  ))}
                </select>
              </div>

              {compareProduct && (
                <div className="pd-compare-table">
                  {[
                    { label: 'Expected Return', a: `${product.expectedReturn}%`, b: `${compareProduct.expectedReturn}%` },
                    { label: 'Risk Level', a: product.riskLevel, b: compareProduct.riskLevel },
                    { label: 'Liquidity', a: product.liquidity, b: compareProduct.liquidity },
                    { label: 'Time Horizon', a: product.timeHorizon, b: compareProduct.timeHorizon },
                    { label: 'Min. Investment', a: formatPKR(product.minInvestment), b: formatPKR(compareProduct.minInvestment) },
                  ].map(row => (
                    <div key={row.label} className="pd-compare-row">
                      <span className="pd-cmp-label">{row.label}</span>
                      <span className="pd-cmp-a">{row.a}</span>
                      <span className="pd-cmp-vs">vs</span>
                      <span className="pd-cmp-b">{row.b}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
